documentation:
Via an AWS managed 2MB S3 JSON: https://website.spot.ec2.aws.a2z.com/spot.json
Caches locally into hourly aws_spot_* files
Response contains all regions and looks like:
{
  "vers": 0.01,
  "config": {
    "rate": "perhr",
    "valueColumns": [
      "linux",
      "mswin"
    ],
    "currencies": [
      "USD"
    ],
    "regions": [
      {
        "region": "us-east-1",
        "footnotes": {
          "*": "notAvailableForCCorCGPU"
        },
        "instanceTypes": [
          {
            "type": "generalCurrentGen",
            "sizes": [
              {
                "size": "m6i.xlarge",
                "valueColumns": [
                  {
                    "name": "linux",
                    "prices": {
                      "USD": "0.0615"
                    }
                  },
                  {
                    "name": "mswin",
                    "prices": {
                      "USD": "0.2032"
                    }
                  }
                ]
              },
              {
                "size": "m6g.xlarge",
                "valueColumns": [
                  {
                    "name": "linux",
                    "prices": {
                      "USD": "0.0378"
                    }
                  },
                  {
                    "name": "mswin",
                    "prices": {
                      "USD": "N/A*"
                    }
                  }
                ]
              },

